package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.api.v1.dto.AdminRequests.MenuRequest; import com.vycepay.admin.application.service.*; import com.vycepay.common.api.*; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Admin menu management APIs. */
@RestController @RequestMapping("/api/admin/v1/menus")
public class MenuController{private final AdminReadService r; private final AdminMutationService m; private final RateLimitService rateLimitService; public MenuController(AdminReadService r,AdminMutationService m,RateLimitService rateLimitService){this.r=r;this.m=m;this.rateLimitService=rateLimitService;} @GetMapping public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> list(){return ResponseEntity.ok(ApiSuccessResponses.ok("MENUS_OK","Menus",r.menus()));} @PostMapping @PreAuthorize("hasAuthority('PERM_admin:manage_menus')") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> create(@Valid @RequestBody MenuRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);Long id=m.createMenu(body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("MENU_CREATED","Menu created",Map.of("id",id)));} @PutMapping("/{id}") @PreAuthorize("hasAuthority('PERM_admin:manage_menus')") public ResponseEntity<ApiSuccessResponse<Void>> update(@PathVariable Long id,@Valid @RequestBody MenuRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);m.updateMenu(id,body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("MENU_UPDATED","Menu updated"));} @DeleteMapping("/{id}") @PreAuthorize("hasAuthority('PERM_admin:manage_menus')") public ResponseEntity<ApiSuccessResponse<Void>> delete(@PathVariable Long id,HttpServletRequest req){rateLimitService.check("mutation",req);m.deleteMenu(id,req);return ResponseEntity.ok(ApiSuccessResponses.ok("MENU_DELETED","Menu deleted"));}}
